import ShaderPad, { PluginContext, TextureSource } from '..';
import {
	calculateBoundingBoxCenter,
	generateGLSLFn,
	getSharedFileset,
	hashOptions,
	isMediaPipeSource,
	MediaPipeSource,
} from './mediapipe-common';
import type { FaceLandmarker, FaceLandmarkerResult, NormalizedLandmark } from '@mediapipe/tasks-vision';

export interface FacePluginOptions {
	modelPath?: string;
	maxFaces?: number;
	minFaceDetectionConfidence?: number;
	minFacePresenceConfidence?: number;
	minTrackingConfidence?: number;
	outputFaceBlendshapes?: boolean;
	outputFacialTransformationMatrixes?: boolean;
	history?: number;
}

const MASK_VERTEX_SHADER = `#version 300 es
in vec2 a_pos;
out vec2 v_uv;
void main() {
	v_uv = a_pos;
	gl_Position = vec4(a_pos * 2.0 - 1.0, 0.0, 1.0);
}`;
const MASK_FRAGMENT_SHADER = `#version 300 es
precision mediump float;
uniform vec4 u_color;
out vec4 outColor;
void main() { outColor = u_color; }`;
const BLIT_FRAGMENT_SHADER = `#version 300 es
precision mediump float;
in vec2 v_uv;
uniform sampler2D u_texture;
out vec4 outColor;
void main() { outColor = texture(u_texture, v_uv); }`;
const FULLSCREEN_TRIANGLES = new Float32Array([0, 0, 1, 0, 0, 1, 0, 1, 1, 0, 1, 1]);

const STANDARD_LANDMARK_COUNT = 478;
const CUSTOM_LANDMARK_COUNT = 2;
const LANDMARK_COUNT = STANDARD_LANDMARK_COUNT + CUSTOM_LANDMARK_COUNT;
const LANDMARKS_TEXTURE_WIDTH = 512;
const N_LANDMARK_METADATA_SLOTS = 1;

const LEFT_EYEBROW_INDICES = [336, 296, 334, 293, 300, 276, 283, 282, 295, 285] as const;
const LEFT_EYE_INDICES = [362, 398, 384, 385, 386, 387, 388, 466, 263, 249, 390, 373, 374, 380, 381, 382] as const;
const RIGHT_EYEBROW_INDICES = [70, 63, 105, 66, 107, 55, 65, 52, 53, 46] as const;
const RIGHT_EYE_INDICES = [33, 246, 161, 160, 159, 158, 157, 173, 133, 155, 154, 153, 145, 144, 163, 7] as const;
const MOUTH_INDICES = [
	61, 185, 40, 39, 37, 0, 267, 269, 270, 409, 291, 375, 321, 405, 314, 17, 84, 181, 91, 146,
] as const;
const INNER_MOUTH_INDICES = [
	78, 191, 80, 81, 82, 13, 312, 311, 310, 415, 308, 324, 318, 402, 317, 14, 87, 178, 88, 95,
] as const;
const ALL_STANDARD_INDICES = Array.from({ length: STANDARD_LANDMARK_COUNT }, (_, i) => i);
const LANDMARK_INDICES = {
	LEFT_EYEBROW: LEFT_EYEBROW_INDICES,
	LEFT_EYE: LEFT_EYE_INDICES,
	LEFT_EYE_CENTER: 473,
	RIGHT_EYEBROW: RIGHT_EYEBROW_INDICES,
	RIGHT_EYE: RIGHT_EYE_INDICES,
	RIGHT_EYE_CENTER: 468,
	NOSE_TIP: 4,
	MOUTH: MOUTH_INDICES,
	INNER_MOUTH: INNER_MOUTH_INDICES,
	// Custom landmarks.
	FACE_CENTER: STANDARD_LANDMARK_COUNT,
	MOUTH_CENTER: STANDARD_LANDMARK_COUNT + 1,
};

/* Face mask channel layout:
- R: additive bitfield for face regions. Since it’s additive, it handles overlapping regions.
- G/B: tessellation ownership. When maxFaces is <= 16, G stores one-hot bits for
  faces 0-7 and B stores one-hot bits for faces 8-15 so overlapping faces
  remain decodable. Above 16 maxFaces, B falls back to storing faceIndex + 1 as
  an additive byte value, which will overcount on overlaps. */
const RED_REGION_NAMES = [
	'OVAL',
	'LEFT_EYEBROW',
	'RIGHT_EYEBROW',
	'LEFT_EYE',
	'RIGHT_EYE',
	'MOUTH',
	'INNER_MOUTH',
] as const;
const GREEN_REGION_NAMES = ['FACE_0', 'FACE_1', 'FACE_2', 'FACE_3', 'FACE_4', 'FACE_5', 'FACE_6', 'FACE_7'] as const;
const BLUE_REGION_NAMES = [
	'FACE_8',
	'FACE_9',
	'FACE_10',
	'FACE_11',
	'FACE_12',
	'FACE_13',
	'FACE_14',
	'FACE_15',
] as const;
const CHANNEL_BIT_SCALE = 255;
const GB_BITMASK_MAX_FACES = GREEN_REGION_NAMES.length + BLUE_REGION_NAMES.length;

function createChannelBitValues<const T extends readonly string[]>(names: T): Record<T[number], number> {
	return Object.fromEntries(names.map((name, i) => [name, 1 << i])) as Record<T[number], number>;
}

function normalizeChannelBitValues<T extends Record<string, number>>(bitValues: T): T {
	return Object.fromEntries(
		Object.entries(bitValues).map(([name, bitValue]) => [name, bitValue / CHANNEL_BIT_SCALE]),
	) as T;
}

const RED_REGION_BIT_VALUES = createChannelBitValues(RED_REGION_NAMES);
const GREEN_REGION_BIT_VALUES = createChannelBitValues(GREEN_REGION_NAMES);
const BLUE_REGION_BIT_VALUES = createChannelBitValues(BLUE_REGION_NAMES);
const RED_CHANNEL_VALUES = normalizeChannelBitValues(RED_REGION_BIT_VALUES);
const GREEN_CHANNEL_VALUES = normalizeChannelBitValues(GREEN_REGION_BIT_VALUES);
const BLUE_CHANNEL_VALUES = normalizeChannelBitValues(BLUE_REGION_BIT_VALUES);

const DEFAULT_FACE_OPTIONS: Required<Omit<FacePluginOptions, 'history'>> = {
	modelPath:
		'https://storage.googleapis.com/mediapipe-models/face_landmarker/face_landmarker/float16/latest/face_landmarker.task',
	maxFaces: 1,
	minFaceDetectionConfidence: 0.5,
	minFacePresenceConfidence: 0.5,
	minTrackingConfidence: 0.5,
	outputFaceBlendshapes: false,
	outputFacialTransformationMatrixes: false,
};

function fanTriangulate(indices: readonly number[]): number[] {
	const tris: number[] = [];
	for (let i = 1; i < indices.length - 1; ++i) {
		tris.push(indices[0], indices[i], indices[i + 1]);
	}
	return tris;
}

type FaceRegion = { indices: number[]; vertices: Float32Array };
let faceRegions: Record<string, FaceRegion> | null = null;
function initFaceRegions(LandmarkerClass: typeof FaceLandmarker): void {
	if (!faceRegions) {
		const tesselationConnections = LandmarkerClass.FACE_LANDMARKS_TESSELATION;
		const tesselation: number[] = [];
		for (let i = 0; i < tesselationConnections.length - 2; i += 3) {
			tesselation.push(
				tesselationConnections[i].start,
				tesselationConnections[i + 1].start,
				tesselationConnections[i + 2].start,
			);
		}
		const ovalIndices = LandmarkerClass.FACE_LANDMARKS_FACE_OVAL.map(({ start }) => start);
		faceRegions = Object.fromEntries(
			Object.entries({
				LEFT_EYEBROW: fanTriangulate(LEFT_EYEBROW_INDICES),
				RIGHT_EYEBROW: fanTriangulate(RIGHT_EYEBROW_INDICES),
				LEFT_EYE: fanTriangulate(LEFT_EYE_INDICES),
				RIGHT_EYE: fanTriangulate(RIGHT_EYE_INDICES),
				MOUTH: fanTriangulate(MOUTH_INDICES),
				INNER_MOUTH: fanTriangulate(INNER_MOUTH_INDICES),
				TESSELATION: tesselation,
				OVAL: fanTriangulate(ovalIndices),
			}).map(([key, indices]) => [key, { indices, vertices: new Float32Array(indices.length * 2) }]),
		);
	}
}

interface MaskRenderer {
	canvas: OffscreenCanvas;
	gl: WebGL2RenderingContext;
	regionProgram: WebGLProgram;
	blitProgram: WebGLProgram;
	regionPositionBuffer: WebGLBuffer;
	quadBuffer: WebGLBuffer;
	regionPositionLocation: number;
	blitPositionLocation: number;
	colorLocation: WebGLUniformLocation;
	textureLocation: WebGLUniformLocation;
	scratchTexture: WebGLTexture;
	scratchFramebuffer: WebGLFramebuffer;
}

interface Detector {
	landmarker: FaceLandmarker;
	mask: MaskRenderer;
	subscribers: Map<Function, boolean>;
	maxFaces: number;
	state: {
		nCalls: number;
		runningMode: 'IMAGE' | 'VIDEO';
		source: MediaPipeSource | null;
		videoTime: number;
		resultTimestamp: number;
		result: FaceLandmarkerResult | null;
		pending: Promise<void>;
		nFaces: number;
	};
	landmarks: {
		data: Float32Array;
		textureHeight: number;
	};
}
const sharedDetectors = new Map<string, Detector>();

function createProgram(gl: WebGL2RenderingContext, vertexSource: string, fragmentSource: string): WebGLProgram {
	const vertexShader = gl.createShader(gl.VERTEX_SHADER)!;
	gl.shaderSource(vertexShader, vertexSource);
	gl.compileShader(vertexShader);

	const fragmentShader = gl.createShader(gl.FRAGMENT_SHADER)!;
	gl.shaderSource(fragmentShader, fragmentSource);
	gl.compileShader(fragmentShader);

	const program = gl.createProgram()!;
	gl.attachShader(program, vertexShader);
	gl.attachShader(program, fragmentShader);
	gl.linkProgram(program);
	gl.deleteShader(vertexShader);
	gl.deleteShader(fragmentShader);
	return program;
}

function initMaskRenderer(canvas: OffscreenCanvas): MaskRenderer {
	const gl = canvas.getContext('webgl2', {
		antialias: false,
		preserveDrawingBuffer: true,
	})!;
	const regionProgram = createProgram(gl, MASK_VERTEX_SHADER, MASK_FRAGMENT_SHADER);
	const blitProgram = createProgram(gl, MASK_VERTEX_SHADER, BLIT_FRAGMENT_SHADER);

	const regionPositionBuffer = gl.createBuffer()!;
	const regionPositionLocation = gl.getAttribLocation(regionProgram, 'a_pos');

	const quadBuffer = gl.createBuffer()!;
	gl.bindBuffer(gl.ARRAY_BUFFER, quadBuffer);
	gl.bufferData(gl.ARRAY_BUFFER, FULLSCREEN_TRIANGLES, gl.STATIC_DRAW);
	const blitPositionLocation = gl.getAttribLocation(blitProgram, 'a_pos');

	const colorLocation = gl.getUniformLocation(regionProgram, 'u_color')!;
	const textureLocation = gl.getUniformLocation(blitProgram, 'u_texture')!;

	const scratchTexture = gl.createTexture()!;
	gl.bindTexture(gl.TEXTURE_2D, scratchTexture);
	gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
	gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
	gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.NEAREST);
	gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.NEAREST);
	gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE, null);

	const scratchFramebuffer = gl.createFramebuffer()!;
	gl.bindFramebuffer(gl.FRAMEBUFFER, scratchFramebuffer);
	gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, scratchTexture, 0);
	gl.bindFramebuffer(gl.FRAMEBUFFER, null);

	gl.useProgram(blitProgram);
	gl.uniform1i(textureLocation, 0);
	gl.colorMask(true, true, true, false);

	return {
		canvas,
		gl,
		regionProgram,
		blitProgram,
		regionPositionBuffer,
		quadBuffer,
		regionPositionLocation,
		blitPositionLocation,
		colorLocation,
		textureLocation,
		scratchTexture,
		scratchFramebuffer,
	};
}

function resizeMaskRenderer(mask: MaskRenderer, width: number, height: number) {
	const { gl, canvas, scratchTexture } = mask;
	if (canvas.width === width && canvas.height === height) return;
	canvas.width = width;
	canvas.height = height;
	gl.bindTexture(gl.TEXTURE_2D, scratchTexture);
	gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, width, height, 0, gl.RGBA, gl.UNSIGNED_BYTE, null);
}

function drawRegionToScratch(
	mask: MaskRenderer,
	landmarksData: Float32Array,
	faceRegion: FaceRegion,
	faceIdx: number,
	r: number,
	g: number,
	b: number,
) {
	const { gl, regionProgram, regionPositionBuffer, regionPositionLocation, colorLocation, scratchFramebuffer } = mask;
	const baseIdx = N_LANDMARK_METADATA_SLOTS + faceIdx * LANDMARK_COUNT;
	const { indices, vertices } = faceRegion;

	gl.bindFramebuffer(gl.FRAMEBUFFER, scratchFramebuffer);
	gl.viewport(0, 0, mask.canvas.width, mask.canvas.height);
	gl.clearColor(0, 0, 0, 0);
	gl.clear(gl.COLOR_BUFFER_BIT);
	gl.useProgram(regionProgram);
	gl.bindBuffer(gl.ARRAY_BUFFER, regionPositionBuffer);
	gl.enableVertexAttribArray(regionPositionLocation);
	gl.vertexAttribPointer(regionPositionLocation, 2, gl.FLOAT, false, 0, 0);
	gl.enable(gl.BLEND);
	gl.blendEquation(gl.MAX);
	gl.blendFunc(gl.ONE, gl.ONE);

	for (let i = 0; i < indices.length; ++i) {
		const landmarkIdx = (baseIdx + indices[i]) * 4;
		vertices[i * 2] = landmarksData[landmarkIdx];
		vertices[i * 2 + 1] = landmarksData[landmarkIdx + 1];
	}
	gl.bufferData(gl.ARRAY_BUFFER, vertices, gl.DYNAMIC_DRAW);
	gl.uniform4f(colorLocation, r, g, b, 1.0);
	gl.drawArrays(gl.TRIANGLES, 0, indices.length);
}

function accumulateScratch(mask: MaskRenderer) {
	const { gl, blitProgram, quadBuffer, blitPositionLocation, scratchTexture } = mask;
	gl.bindFramebuffer(gl.FRAMEBUFFER, null);
	gl.viewport(0, 0, mask.canvas.width, mask.canvas.height);
	gl.useProgram(blitProgram);
	gl.bindBuffer(gl.ARRAY_BUFFER, quadBuffer);
	gl.enableVertexAttribArray(blitPositionLocation);
	gl.vertexAttribPointer(blitPositionLocation, 2, gl.FLOAT, false, 0, 0);
	gl.activeTexture(gl.TEXTURE0);
	gl.bindTexture(gl.TEXTURE_2D, scratchTexture);
	gl.enable(gl.BLEND);
	gl.blendEquation(gl.FUNC_ADD);
	gl.blendFunc(gl.ONE, gl.ONE);
	gl.drawArrays(gl.TRIANGLES, 0, 6);
}

function updateLandmarksData(detector: Detector, faces: NormalizedLandmark[][]) {
	const data = detector.landmarks.data;
	const nFaces = faces.length;
	data[0] = nFaces;

	for (let faceIdx = 0; faceIdx < nFaces; ++faceIdx) {
		const landmarks = faces[faceIdx];
		for (let landmarkIdx = 0; landmarkIdx < STANDARD_LANDMARK_COUNT; ++landmarkIdx) {
			const landmark = landmarks[landmarkIdx];
			const dataIdx = (N_LANDMARK_METADATA_SLOTS + faceIdx * LANDMARK_COUNT + landmarkIdx) * 4;
			data[dataIdx] = landmark.x;
			data[dataIdx + 1] = 1 - landmark.y;
			data[dataIdx + 2] = landmark.z ?? 0;
			data[dataIdx + 3] = landmark.visibility ?? 1;
		}

		const faceCenter = calculateBoundingBoxCenter(
			data,
			faceIdx,
			ALL_STANDARD_INDICES,
			LANDMARK_COUNT,
			N_LANDMARK_METADATA_SLOTS,
		);
		data.set(faceCenter, (N_LANDMARK_METADATA_SLOTS + faceIdx * LANDMARK_COUNT + LANDMARK_INDICES.FACE_CENTER) * 4);

		const mouthCenter = calculateBoundingBoxCenter(data, faceIdx, INNER_MOUTH_INDICES, LANDMARK_COUNT, 1);
		data.set(
			mouthCenter,
			(N_LANDMARK_METADATA_SLOTS + faceIdx * LANDMARK_COUNT + LANDMARK_INDICES.MOUTH_CENTER) * 4,
		);
	}

	detector.state.nFaces = nFaces;
}

function updateMask(detector: Detector, width: number, height: number) {
	const {
		mask,
		maxFaces,
		landmarks,
		state: { nFaces },
	} = detector;
	const { gl, canvas: maskCanvas } = mask;
	const { data: landmarksData } = landmarks;

	resizeMaskRenderer(mask, width, height);
	gl.bindFramebuffer(gl.FRAMEBUFFER, null);
	gl.viewport(0, 0, maskCanvas.width, maskCanvas.height);
	gl.clearColor(0, 0, 0, 0);
	gl.clear(gl.COLOR_BUFFER_BIT);

	if (!faceRegions) return;

	const useTesselationBitmask = maxFaces <= GB_BITMASK_MAX_FACES;
	for (let faceIdx = 0; faceIdx < nFaces; ++faceIdx) {
		const g =
			useTesselationBitmask && faceIdx < GREEN_REGION_NAMES.length
				? GREEN_CHANNEL_VALUES[GREEN_REGION_NAMES[faceIdx]]
				: 0;
		const b = useTesselationBitmask
			? faceIdx < GREEN_REGION_NAMES.length
				? 0
				: BLUE_CHANNEL_VALUES[BLUE_REGION_NAMES[faceIdx - GREEN_REGION_NAMES.length]]
			: (faceIdx + 1) / CHANNEL_BIT_SCALE;

		drawRegionToScratch(mask, landmarksData, faceRegions.TESSELATION, faceIdx, 0, g, b);
		accumulateScratch(mask);
		drawRegionToScratch(mask, landmarksData, faceRegions.OVAL, faceIdx, RED_CHANNEL_VALUES.OVAL, 0, 0);
		accumulateScratch(mask);
		drawRegionToScratch(
			mask,
			landmarksData,
			faceRegions.LEFT_EYEBROW,
			faceIdx,
			RED_CHANNEL_VALUES.LEFT_EYEBROW,
			0,
			0,
		);
		accumulateScratch(mask);
		drawRegionToScratch(
			mask,
			landmarksData,
			faceRegions.RIGHT_EYEBROW,
			faceIdx,
			RED_CHANNEL_VALUES.RIGHT_EYEBROW,
			0,
			0,
		);
		accumulateScratch(mask);
		drawRegionToScratch(mask, landmarksData, faceRegions.LEFT_EYE, faceIdx, RED_CHANNEL_VALUES.LEFT_EYE, g, b);
		accumulateScratch(mask);
		drawRegionToScratch(mask, landmarksData, faceRegions.RIGHT_EYE, faceIdx, RED_CHANNEL_VALUES.RIGHT_EYE, g, b);
		accumulateScratch(mask);
		drawRegionToScratch(mask, landmarksData, faceRegions.MOUTH, faceIdx, RED_CHANNEL_VALUES.MOUTH, 0, 0);
		accumulateScratch(mask);
		drawRegionToScratch(
			mask,
			landmarksData,
			faceRegions.INNER_MOUTH,
			faceIdx,
			RED_CHANNEL_VALUES.INNER_MOUTH,
			g,
			b,
		);
		accumulateScratch(mask);
	}
}

function face(config: { textureName: string; options?: FacePluginOptions }) {
	const { textureName, options: { history, ...mediapipeOptions } = {} } = config;
	const options = { ...DEFAULT_FACE_OPTIONS, ...mediapipeOptions };
	const optionsKey = hashOptions({ ...options, textureName });

	const nLandmarksMax = options.maxFaces * LANDMARK_COUNT + N_LANDMARK_METADATA_SLOTS;
	const textureHeight = Math.ceil(nLandmarksMax / LANDMARKS_TEXTURE_WIDTH);

	return function (shaderPad: ShaderPad, context: PluginContext) {
		const { injectGLSL, emitHook, updateTexturesInternal } = context;

		const existingDetector = sharedDetectors.get(optionsKey);
		const landmarksData =
			existingDetector?.landmarks.data ?? new Float32Array(LANDMARKS_TEXTURE_WIDTH * textureHeight * 4);
		const maskCanvas = existingDetector?.mask.canvas ?? new OffscreenCanvas(1, 1);
		let detector: Detector | null = null;
		let destroyed = false;
		let skipHistoryWrite = false;

		function onResult(singleHistoryWriteIndex?: number) {
			if (!detector) return;
			const nFaces = detector.state.nFaces;
			const nSlots = nFaces * LANDMARK_COUNT + N_LANDMARK_METADATA_SLOTS;
			const rowsToUpdate = Math.ceil(nSlots / LANDMARKS_TEXTURE_WIDTH);
			let historyWriteIndex: number | number[] | undefined = singleHistoryWriteIndex;
			if (typeof historyWriteIndex === 'undefined' && pendingBackfillSlots.length > 0) {
				historyWriteIndex = pendingBackfillSlots;
				pendingBackfillSlots = [];
			}
			updateTexturesInternal(
				{
					u_faceLandmarksTex: {
						data: detector.landmarks.data,
						width: LANDMARKS_TEXTURE_WIDTH,
						height: rowsToUpdate,
						isPartial: true,
					},
					u_faceMask: detector.mask.canvas,
				},
				history ? { skipHistoryWrite, historyWriteIndex } : undefined,
			);
			shaderPad.updateUniforms({ u_nFaces: nFaces });
			emitHook('face:result', detector.state.result);
		}

		async function initializeDetector() {
			if (sharedDetectors.has(optionsKey)) {
				detector = sharedDetectors.get(optionsKey)!;
			} else {
				const [mediaPipe, { FaceLandmarker }] = await Promise.all([
					getSharedFileset(),
					import('@mediapipe/tasks-vision'),
				]);
				if (destroyed) return;

				const faceLandmarker = await FaceLandmarker.createFromOptions(mediaPipe, {
					baseOptions: {
						modelAssetPath: options.modelPath,
						delegate: 'GPU',
					},
					runningMode: 'VIDEO',
					numFaces: options.maxFaces,
					minFaceDetectionConfidence: options.minFaceDetectionConfidence,
					minFacePresenceConfidence: options.minFacePresenceConfidence,
					minTrackingConfidence: options.minTrackingConfidence,
					outputFaceBlendshapes: options.outputFaceBlendshapes,
					outputFacialTransformationMatrixes: options.outputFacialTransformationMatrixes,
				});
				if (destroyed) {
					faceLandmarker.close();
					return;
				}

				detector = {
					landmarker: faceLandmarker,
					mask: initMaskRenderer(maskCanvas),
					subscribers: new Map(),
					maxFaces: options.maxFaces,
					state: {
						nCalls: 0,
						runningMode: 'VIDEO',
						source: null,
						videoTime: -1,
						resultTimestamp: 0,
						result: null,
						pending: Promise.resolve(),
						nFaces: 0,
					},
					landmarks: {
						data: landmarksData,
						textureHeight,
					},
				};

				initFaceRegions(FaceLandmarker);
				sharedDetectors.set(optionsKey, detector);
			}

			detector.subscribers.set(onResult, false);
		}
		const initPromise = initializeDetector();

		async function detectFaces(source: MediaPipeSource) {
			const now = performance.now();
			await initPromise;
			if (!detector) return;
			const callOrder = ++detector.state.nCalls;

			detector.state.pending = detector.state.pending.then(async () => {
				if (!detector || callOrder !== detector.state.nCalls) return;

				const requiredMode = source instanceof HTMLVideoElement ? 'VIDEO' : 'IMAGE';
				if (detector.state.runningMode !== requiredMode) {
					detector.state.runningMode = requiredMode;
					await detector.landmarker.setOptions({
						runningMode: requiredMode,
					});
				}

				let shouldDetect = false;

				if (source !== detector.state.source) {
					detector.state.source = source;
					detector.state.videoTime = -1;
					shouldDetect = true;
				} else if (source instanceof HTMLVideoElement) {
					if (source.currentTime !== detector.state.videoTime) {
						detector.state.videoTime = source.currentTime;
						shouldDetect = true;
					}
				} else if (!(source instanceof HTMLImageElement)) {
					if (now - detector.state.resultTimestamp > 2) {
						shouldDetect = true;
					}
				}

				if (shouldDetect) {
					let result: FaceLandmarkerResult | undefined;
					let width: number, height: number;
					if (source instanceof HTMLVideoElement) {
						if (source.videoWidth === 0 || source.videoHeight === 0 || source.readyState < 2) return;
						width = source.videoWidth;
						height = source.videoHeight;
						result = detector.landmarker.detectForVideo(source, now);
					} else {
						if (source.width === 0 || source.height === 0) return;
						width = source.width;
						height = source.height;
						result = detector.landmarker.detect(source);
					}

					if (result) {
						detector.state.resultTimestamp = now;
						detector.state.result = result;
						updateLandmarksData(detector, result.faceLandmarks);
						updateMask(detector, width, height);
						for (const cb of detector.subscribers.keys()) {
							cb();
							detector.subscribers.set(cb, true);
						}
					}
				} else if (detector.state.result) {
					for (const [cb, hasCalled] of detector.subscribers.entries()) {
						if (!hasCalled) {
							cb();
							detector.subscribers.set(cb, true);
						}
					}
				}
			});

			await detector.state.pending;
		}

		shaderPad.on('_init', () => {
			shaderPad.initializeUniform('u_maxFaces', 'int', options.maxFaces);
			shaderPad.initializeUniform('u_nFaces', 'int', 0);
			shaderPad.initializeTexture(
				'u_faceLandmarksTex',
				{
					data: landmarksData,
					width: LANDMARKS_TEXTURE_WIDTH,
					height: textureHeight,
				},
				{
					internalFormat: 'RGBA32F',
					type: 'FLOAT',
					minFilter: 'NEAREST',
					magFilter: 'NEAREST',
					history,
				},
			);
			shaderPad.initializeTexture('u_faceMask', maskCanvas, {
				minFilter: 'NEAREST',
				magFilter: 'NEAREST',
				history,
			});
			initPromise.then(() => {
				if (destroyed || !detector) return;
				emitHook('face:ready');
			});
		});

		let historyWriteCounter = 0;
		let pendingBackfillSlots: number[] = [];
		const writeToHistory = () => {
			if (!history) return;
			onResult(historyWriteCounter); // Write stale data immediately.
			pendingBackfillSlots.push(historyWriteCounter); // Queue up backfill with more recent data.
			historyWriteCounter = (historyWriteCounter + 1) % (history + 1);
		};

		shaderPad.on('initializeTexture', (name: string, source: TextureSource) => {
			if (name === textureName && isMediaPipeSource(source)) {
				writeToHistory();
				detectFaces(source);
			}
		});

		shaderPad.on(
			'updateTextures',
			(updates: Record<string, TextureSource>, options?: { skipHistoryWrite?: boolean }) => {
				const source = updates[textureName];
				if (isMediaPipeSource(source)) {
					skipHistoryWrite = options?.skipHistoryWrite ?? false;
					if (!skipHistoryWrite) writeToHistory();
					detectFaces(source);
				}
			},
		);

		shaderPad.on('destroy', () => {
			destroyed = true;
			if (detector) {
				detector.subscribers.delete(onResult);
				if (detector.subscribers.size === 0) {
					detector.landmarker.close();
					detector.mask.gl.deleteProgram(detector.mask.regionProgram);
					detector.mask.gl.deleteProgram(detector.mask.blitProgram);
					detector.mask.gl.deleteBuffer(detector.mask.regionPositionBuffer);
					detector.mask.gl.deleteBuffer(detector.mask.quadBuffer);
					detector.mask.gl.deleteTexture(detector.mask.scratchTexture);
					detector.mask.gl.deleteFramebuffer(detector.mask.scratchFramebuffer);
					sharedDetectors.delete(optionsKey);
				}
			}
			detector = null;
		});

		const { fn, historyParams } = generateGLSLFn(history);
		const sampleMask = history ? `_sampleFaceMask(pos, framesAgo)` : `texture(u_faceMask, pos)`;
		const decodeFaceBitIndex = Array.from(
			{ length: GB_BITMASK_MAX_FACES - 1 },
			(_, i) => `step(${2 ** (i + 1)}.0, faceBitF)`,
		).join(' + ');
		const decodeFaceIndex =
			options.maxFaces <= GB_BITMASK_MAX_FACES
				? `uint faceBits = (uint(mask.b * ${CHANNEL_BIT_SCALE}.0 + 0.5) << 8) | uint(mask.g * ${CHANNEL_BIT_SCALE}.0 + 0.5);
	uint faceBit = faceBits & (~faceBits + 1u);
	float faceBitF = float(faceBit);
	float hasFace = sign(faceBitF);
	float faceIndex = ${decodeFaceBitIndex} - (1.0 - hasFace);`
				: `float faceIndex = float(int(uint(mask.b * ${CHANNEL_BIT_SCALE}.0 + 0.5)) - 1);`;

		const checkAt = (fnName: string, ...regionNames: (keyof typeof RED_REGION_BIT_VALUES)[]) =>
			fn(
				'vec2',
				`${fnName}At`,
				'vec2 pos',
				`vec4 mask = ${sampleMask};
	${decodeFaceIndex}
	uint bits = uint(mask.r * ${CHANNEL_BIT_SCALE}.0 + 0.5);
	float hit = sign(float(bits & ${regionNames.reduce(
		(mask, regionName) => mask | RED_REGION_BIT_VALUES[regionName],
		0,
	)}u));
	return vec2(hit, mix(-1.0, faceIndex, hit));`,
			);

		const combineLeftRight = (fnName: string, leftFn: string, rightFn: string) =>
			fn(
				'vec2',
				`${fnName}At`,
				'vec2 pos',
				`vec2 left = ${leftFn}(pos${historyParams});
	vec2 right = ${rightFn}(pos${historyParams});
	return mix(right, left, left.x);`,
			);

		const checkIn = (fnNames: string[]) =>
			fnNames
				.map(fnName =>
					fn(
						'float',
						`in${fnName[0].toUpperCase() + fnName.slice(1)}`,
						'vec2 pos',
						`vec2 a = ${fnName}At(pos${historyParams}); return step(0.0, a.y) * a.x;`,
					),
				)
				.join('\n');

		injectGLSL(`
uniform int u_maxFaces;
uniform int u_nFaces;
uniform highp sampler2D${history ? 'Array' : ''} u_faceLandmarksTex;${
			history
				? `
uniform int u_faceLandmarksTexFrameOffset;`
				: ''
		}
uniform mediump sampler2D${history ? 'Array' : ''} u_faceMask;${
			history
				? `
uniform int u_faceMaskFrameOffset;`
				: ''
		}

#define FACE_LANDMARK_L_EYE_CENTER ${LANDMARK_INDICES.LEFT_EYE_CENTER}
#define FACE_LANDMARK_R_EYE_CENTER ${LANDMARK_INDICES.RIGHT_EYE_CENTER}
#define FACE_LANDMARK_NOSE_TIP ${LANDMARK_INDICES.NOSE_TIP}
#define FACE_LANDMARK_FACE_CENTER ${LANDMARK_INDICES.FACE_CENTER}
#define FACE_LANDMARK_MOUTH_CENTER ${LANDMARK_INDICES.MOUTH_CENTER}

${fn(
	'int',
	'nFacesAt',
	'',
	history
		? `
	int layer = (u_faceLandmarksTexFrameOffset - framesAgo + ${history + 1}) % ${history + 1};
	return int(texelFetch(u_faceLandmarksTex, ivec3(0, 0, layer), 0).r + 0.5);`
		: `
	return int(texelFetch(u_faceLandmarksTex, ivec2(0, 0), 0).r + 0.5);`,
)}
${fn(
	'vec4',
	'faceLandmark',
	'int faceIndex, int landmarkIndex',
	`int i = ${N_LANDMARK_METADATA_SLOTS} + faceIndex * ${LANDMARK_COUNT} + landmarkIndex;
	int x = i % ${LANDMARKS_TEXTURE_WIDTH};
	int y = i / ${LANDMARKS_TEXTURE_WIDTH};${
		history
			? `
	int layer = (u_faceLandmarksTexFrameOffset - framesAgo + ${history + 1}) % ${history + 1};
	return texelFetch(u_faceLandmarksTex, ivec3(x, y, layer), 0);`
			: `
	return texelFetch(u_faceLandmarksTex, ivec2(x, y), 0);`
	}`,
)}
${
	history
		? `
vec4 _sampleFaceMask(vec2 pos, int framesAgo) {
	int layer = (u_faceMaskFrameOffset - framesAgo + ${history + 1}) % ${history + 1};
	return texture(u_faceMask, vec3(pos, float(layer)));
}
`
		: ''
}
${checkAt('leftEyebrow', 'LEFT_EYEBROW')}
${checkAt('rightEyebrow', 'RIGHT_EYEBROW')}
${checkAt('leftEye', 'LEFT_EYE')}
${checkAt('rightEye', 'RIGHT_EYE')}
${checkAt('lips', 'MOUTH')}
${checkAt('mouth', 'MOUTH', 'INNER_MOUTH')}
${checkAt('innerMouth', 'INNER_MOUTH')}
${checkAt('faceOval', 'OVAL')}
${fn(
	'vec2',
	'faceAt',
	'vec2 pos',
	`vec4 mask = ${sampleMask};
	${decodeFaceIndex}
	return vec2(step(0.0, faceIndex), faceIndex);`,
)}
${combineLeftRight('eye', 'leftEyeAt', 'rightEyeAt')}
${combineLeftRight('eyebrow', 'leftEyebrowAt', 'rightEyebrowAt')}
${checkIn(['eyebrow', 'eye', 'mouth', 'innerMouth', 'lips', 'face'])}`);
	};
}

export default face;
